function About() {
    return (
        <section className="container py-5">
            <div className="row justify-content-center">
                <div className="col-md-8 text-center">
                    <h2 className="mb-4">Sobre mí</h2>
                    <p className="lead">Soy ingeniero de software dedicado principalmente al desarrollo de aplicaciones en java para suplir
                        necesidades de negocio. Experiencia en Spring Boot, Java, SQL , y Python.</p>
                </div>
            </div>
        </section>
    );
}

export default About;
